/**
 * @file fft_radix16_avx2_ct_n1_il.h
 * @brief DFT-16 AVX2 n1 interleaved-complex (4x4 CT)
 *
 * Same 4x4 CT structure as split-complex ct_n1, but native IL layout.
 * k-step=2 (vs 4 for split)
 * Generated by gen_radix16.py --variant ct_n1_il
 */

#ifndef FFT_RADIX16_AVX2_CT_N1_IL_H
#define FFT_RADIX16_AVX2_CT_N1_IL_H

#include <immintrin.h>

#ifndef FFT_W16_TWIDDLES_DEFINED
#define FFT_W16_TWIDDLES_DEFINED
static const double W16_1_re = 9.23879532511286738483e-01;
static const double W16_1_im = -3.82683432365089781779e-01;
static const double W16_3_re = 3.82683432365089837290e-01;
static const double W16_3_im = -9.23879532511286738483e-01;
static const double W16_9_re = -9.23879532511286849505e-01;
static const double W16_9_im = 3.82683432365089670757e-01;
#endif

#ifndef R16A_IL_CT_LD
#define R16A_IL_CT_LD(p) _mm256_loadu_pd(p)
#define R16A_IL_CT_ST(p,v) _mm256_storeu_pd((p),(v))
#endif

static __attribute__((target("avx2,fma"))) void
radix16_n1_il_fwd_avx2(
    const double * __restrict__ in,
    double * __restrict__ out,
    size_t is, size_t os, size_t vl)
{
    const __m256d sign_odd = _mm256_castsi256_pd(_mm256_set_epi64x(
        (long long)0x8000000000000000ULL, 0, (long long)0x8000000000000000ULL, 0));
    const __m256d sign_even = _mm256_castsi256_pd(_mm256_set_epi64x(
        0, (long long)0x8000000000000000ULL, 0, (long long)0x8000000000000000ULL));
    const __m256d sign_all = _mm256_castsi256_pd(
        _mm256_set1_epi64x((long long)0x8000000000000000ULL));
    const __m256d sqrt2_inv = _mm256_set1_pd(0.70710678118654752440);
    (void)sign_all;

    const __m256d tw_W16_1_rr = _mm256_set1_pd(W16_1_re);
    const __m256d tw_W16_1_in = _mm256_xor_pd(_mm256_set1_pd(W16_1_im), sign_even);
    const __m256d tw_W16_3_rr = _mm256_set1_pd(W16_3_re);
    const __m256d tw_W16_3_in = _mm256_xor_pd(_mm256_set1_pd(W16_3_im), sign_even);
    const __m256d tw_W16_9_rr = _mm256_set1_pd(W16_9_re);
    const __m256d tw_W16_9_in = _mm256_xor_pd(_mm256_set1_pd(W16_9_im), sign_even);

    __attribute__((aligned(32))) double spill[64];

    __m256d x0, x1, x2, x3;

    for (size_t k = 0; k < vl; k += 2) {
        const size_t off = k * 2;

        /* sub-FFT n2=0 */
        x0 = R16A_IL_CT_LD(&in[(0*is)*2 + off]);
        x1 = R16A_IL_CT_LD(&in[(4*is)*2 + off]);
        x2 = R16A_IL_CT_LD(&in[(8*is)*2 + off]);
        x3 = R16A_IL_CT_LD(&in[(12*is)*2 + off]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d nj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_odd);
            x1=_mm256_add_pd(t1,nj); x3=_mm256_sub_pd(t1,nj); }
        }
        _mm256_store_pd(&spill[0*4], x0);
        _mm256_store_pd(&spill[1*4], x1);
        _mm256_store_pd(&spill[2*4], x2);
        _mm256_store_pd(&spill[3*4], x3);

        /* sub-FFT n2=1 */
        x0 = R16A_IL_CT_LD(&in[(1*is)*2 + off]);
        x1 = R16A_IL_CT_LD(&in[(5*is)*2 + off]);
        x2 = R16A_IL_CT_LD(&in[(9*is)*2 + off]);
        x3 = R16A_IL_CT_LD(&in[(13*is)*2 + off]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d nj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_odd);
            x1=_mm256_add_pd(t1,nj); x3=_mm256_sub_pd(t1,nj); }
        }
        _mm256_store_pd(&spill[4*4], x0);
        _mm256_store_pd(&spill[5*4], x1);
        _mm256_store_pd(&spill[6*4], x2);
        _mm256_store_pd(&spill[7*4], x3);

        /* sub-FFT n2=2 */
        x0 = R16A_IL_CT_LD(&in[(2*is)*2 + off]);
        x1 = R16A_IL_CT_LD(&in[(6*is)*2 + off]);
        x2 = R16A_IL_CT_LD(&in[(10*is)*2 + off]);
        x3 = R16A_IL_CT_LD(&in[(14*is)*2 + off]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d nj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_odd);
            x1=_mm256_add_pd(t1,nj); x3=_mm256_sub_pd(t1,nj); }
        }
        _mm256_store_pd(&spill[8*4], x0);
        _mm256_store_pd(&spill[9*4], x1);
        _mm256_store_pd(&spill[10*4], x2);
        _mm256_store_pd(&spill[11*4], x3);

        /* sub-FFT n2=3 */
        x0 = R16A_IL_CT_LD(&in[(3*is)*2 + off]);
        x1 = R16A_IL_CT_LD(&in[(7*is)*2 + off]);
        x2 = R16A_IL_CT_LD(&in[(11*is)*2 + off]);
        x3 = R16A_IL_CT_LD(&in[(15*is)*2 + off]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d nj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_odd);
            x1=_mm256_add_pd(t1,nj); x3=_mm256_sub_pd(t1,nj); }
        }
        _mm256_store_pd(&spill[12*4], x0);
        _mm256_store_pd(&spill[13*4], x1);
        _mm256_store_pd(&spill[14*4], x2);
        _mm256_store_pd(&spill[15*4], x3);

        /* PASS 2 */
        /* column k1=0 */
        x0 = _mm256_load_pd(&spill[0*4]);
        x1 = _mm256_load_pd(&spill[4*4]);
        x2 = _mm256_load_pd(&spill[8*4]);
        x3 = _mm256_load_pd(&spill[12*4]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d nj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_odd);
            x1=_mm256_add_pd(t1,nj); x3=_mm256_sub_pd(t1,nj); }
        }
        R16A_IL_CT_ST(&out[(0*os)*2 + off], x0);
        R16A_IL_CT_ST(&out[(4*os)*2 + off], x1);
        R16A_IL_CT_ST(&out[(8*os)*2 + off], x2);
        R16A_IL_CT_ST(&out[(12*os)*2 + off], x3);

        /* column k1=1 */
        x0 = _mm256_load_pd(&spill[1*4]);
        x1 = _mm256_load_pd(&spill[5*4]);
        x2 = _mm256_load_pd(&spill[9*4]);
        x3 = _mm256_load_pd(&spill[13*4]);
        { __m256d zs=_mm256_permute_pd(x1,0x5);
          x1=_mm256_fmadd_pd(x1,tw_W16_1_rr,_mm256_mul_pd(zs,tw_W16_1_in)); }
        { __m256d zs=_mm256_permute_pd(x2,0x5);
          __m256d s=_mm256_add_pd(x2,zs), d=_mm256_sub_pd(x2,zs);
          x2=_mm256_mul_pd(_mm256_blend_pd(s,d,0xA),sqrt2_inv); }
        { __m256d zs=_mm256_permute_pd(x3,0x5);
          x3=_mm256_fmadd_pd(x3,tw_W16_3_rr,_mm256_mul_pd(zs,tw_W16_3_in)); }
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d nj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_odd);
            x1=_mm256_add_pd(t1,nj); x3=_mm256_sub_pd(t1,nj); }
        }
        R16A_IL_CT_ST(&out[(1*os)*2 + off], x0);
        R16A_IL_CT_ST(&out[(5*os)*2 + off], x1);
        R16A_IL_CT_ST(&out[(9*os)*2 + off], x2);
        R16A_IL_CT_ST(&out[(13*os)*2 + off], x3);

        /* column k1=2 */
        x0 = _mm256_load_pd(&spill[2*4]);
        x1 = _mm256_load_pd(&spill[6*4]);
        x2 = _mm256_load_pd(&spill[10*4]);
        x3 = _mm256_load_pd(&spill[14*4]);
        { __m256d zs=_mm256_permute_pd(x1,0x5);
          __m256d s=_mm256_add_pd(x1,zs), d=_mm256_sub_pd(x1,zs);
          x1=_mm256_mul_pd(_mm256_blend_pd(s,d,0xA),sqrt2_inv); }
        x2 = _mm256_xor_pd(_mm256_permute_pd(x2,0x5), sign_odd);
        { __m256d zs=_mm256_permute_pd(x3,0x5);
          __m256d s=_mm256_add_pd(x3,zs), d=_mm256_sub_pd(zs,x3);
          x3=_mm256_mul_pd(_mm256_blend_pd(d,_mm256_xor_pd(s,sign_all),0xA),sqrt2_inv); }
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d nj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_odd);
            x1=_mm256_add_pd(t1,nj); x3=_mm256_sub_pd(t1,nj); }
        }
        R16A_IL_CT_ST(&out[(2*os)*2 + off], x0);
        R16A_IL_CT_ST(&out[(6*os)*2 + off], x1);
        R16A_IL_CT_ST(&out[(10*os)*2 + off], x2);
        R16A_IL_CT_ST(&out[(14*os)*2 + off], x3);

        /* column k1=3 */
        x0 = _mm256_load_pd(&spill[3*4]);
        x1 = _mm256_load_pd(&spill[7*4]);
        x2 = _mm256_load_pd(&spill[11*4]);
        x3 = _mm256_load_pd(&spill[15*4]);
        { __m256d zs=_mm256_permute_pd(x1,0x5);
          x1=_mm256_fmadd_pd(x1,tw_W16_3_rr,_mm256_mul_pd(zs,tw_W16_3_in)); }
        { __m256d zs=_mm256_permute_pd(x2,0x5);
          __m256d s=_mm256_add_pd(x2,zs), d=_mm256_sub_pd(zs,x2);
          x2=_mm256_mul_pd(_mm256_blend_pd(d,_mm256_xor_pd(s,sign_all),0xA),sqrt2_inv); }
        { __m256d zs=_mm256_permute_pd(x3,0x5);
          x3=_mm256_fmadd_pd(x3,tw_W16_9_rr,_mm256_mul_pd(zs,tw_W16_9_in)); }
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d nj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_odd);
            x1=_mm256_add_pd(t1,nj); x3=_mm256_sub_pd(t1,nj); }
        }
        R16A_IL_CT_ST(&out[(3*os)*2 + off], x0);
        R16A_IL_CT_ST(&out[(7*os)*2 + off], x1);
        R16A_IL_CT_ST(&out[(11*os)*2 + off], x2);
        R16A_IL_CT_ST(&out[(15*os)*2 + off], x3);

    }
}

static __attribute__((target("avx2,fma"))) void
radix16_n1_il_bwd_avx2(
    const double * __restrict__ in,
    double * __restrict__ out,
    size_t is, size_t os, size_t vl)
{
    const __m256d sign_odd = _mm256_castsi256_pd(_mm256_set_epi64x(
        (long long)0x8000000000000000ULL, 0, (long long)0x8000000000000000ULL, 0));
    const __m256d sign_even = _mm256_castsi256_pd(_mm256_set_epi64x(
        0, (long long)0x8000000000000000ULL, 0, (long long)0x8000000000000000ULL));
    const __m256d sign_all = _mm256_castsi256_pd(
        _mm256_set1_epi64x((long long)0x8000000000000000ULL));
    const __m256d sqrt2_inv = _mm256_set1_pd(0.70710678118654752440);
    (void)sign_all;

    const __m256d tw_W16_1_rr = _mm256_set1_pd(W16_1_re);
    const __m256d tw_W16_1_in = _mm256_xor_pd(_mm256_set1_pd(W16_1_im), sign_odd);
    const __m256d tw_W16_3_rr = _mm256_set1_pd(W16_3_re);
    const __m256d tw_W16_3_in = _mm256_xor_pd(_mm256_set1_pd(W16_3_im), sign_odd);
    const __m256d tw_W16_9_rr = _mm256_set1_pd(W16_9_re);
    const __m256d tw_W16_9_in = _mm256_xor_pd(_mm256_set1_pd(W16_9_im), sign_odd);

    __attribute__((aligned(32))) double spill[64];

    __m256d x0, x1, x2, x3;

    for (size_t k = 0; k < vl; k += 2) {
        const size_t off = k * 2;

        /* sub-FFT n2=0 */
        x0 = R16A_IL_CT_LD(&in[(0*is)*2 + off]);
        x1 = R16A_IL_CT_LD(&in[(4*is)*2 + off]);
        x2 = R16A_IL_CT_LD(&in[(8*is)*2 + off]);
        x3 = R16A_IL_CT_LD(&in[(12*is)*2 + off]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d pj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_even);
            x1=_mm256_add_pd(t1,pj); x3=_mm256_sub_pd(t1,pj); }
        }
        _mm256_store_pd(&spill[0*4], x0);
        _mm256_store_pd(&spill[1*4], x1);
        _mm256_store_pd(&spill[2*4], x2);
        _mm256_store_pd(&spill[3*4], x3);

        /* sub-FFT n2=1 */
        x0 = R16A_IL_CT_LD(&in[(1*is)*2 + off]);
        x1 = R16A_IL_CT_LD(&in[(5*is)*2 + off]);
        x2 = R16A_IL_CT_LD(&in[(9*is)*2 + off]);
        x3 = R16A_IL_CT_LD(&in[(13*is)*2 + off]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d pj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_even);
            x1=_mm256_add_pd(t1,pj); x3=_mm256_sub_pd(t1,pj); }
        }
        _mm256_store_pd(&spill[4*4], x0);
        _mm256_store_pd(&spill[5*4], x1);
        _mm256_store_pd(&spill[6*4], x2);
        _mm256_store_pd(&spill[7*4], x3);

        /* sub-FFT n2=2 */
        x0 = R16A_IL_CT_LD(&in[(2*is)*2 + off]);
        x1 = R16A_IL_CT_LD(&in[(6*is)*2 + off]);
        x2 = R16A_IL_CT_LD(&in[(10*is)*2 + off]);
        x3 = R16A_IL_CT_LD(&in[(14*is)*2 + off]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d pj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_even);
            x1=_mm256_add_pd(t1,pj); x3=_mm256_sub_pd(t1,pj); }
        }
        _mm256_store_pd(&spill[8*4], x0);
        _mm256_store_pd(&spill[9*4], x1);
        _mm256_store_pd(&spill[10*4], x2);
        _mm256_store_pd(&spill[11*4], x3);

        /* sub-FFT n2=3 */
        x0 = R16A_IL_CT_LD(&in[(3*is)*2 + off]);
        x1 = R16A_IL_CT_LD(&in[(7*is)*2 + off]);
        x2 = R16A_IL_CT_LD(&in[(11*is)*2 + off]);
        x3 = R16A_IL_CT_LD(&in[(15*is)*2 + off]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d pj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_even);
            x1=_mm256_add_pd(t1,pj); x3=_mm256_sub_pd(t1,pj); }
        }
        _mm256_store_pd(&spill[12*4], x0);
        _mm256_store_pd(&spill[13*4], x1);
        _mm256_store_pd(&spill[14*4], x2);
        _mm256_store_pd(&spill[15*4], x3);

        /* PASS 2 */
        /* column k1=0 */
        x0 = _mm256_load_pd(&spill[0*4]);
        x1 = _mm256_load_pd(&spill[4*4]);
        x2 = _mm256_load_pd(&spill[8*4]);
        x3 = _mm256_load_pd(&spill[12*4]);
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d pj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_even);
            x1=_mm256_add_pd(t1,pj); x3=_mm256_sub_pd(t1,pj); }
        }
        R16A_IL_CT_ST(&out[(0*os)*2 + off], x0);
        R16A_IL_CT_ST(&out[(4*os)*2 + off], x1);
        R16A_IL_CT_ST(&out[(8*os)*2 + off], x2);
        R16A_IL_CT_ST(&out[(12*os)*2 + off], x3);

        /* column k1=1 */
        x0 = _mm256_load_pd(&spill[1*4]);
        x1 = _mm256_load_pd(&spill[5*4]);
        x2 = _mm256_load_pd(&spill[9*4]);
        x3 = _mm256_load_pd(&spill[13*4]);
        { __m256d zs=_mm256_permute_pd(x1,0x5);
          x1=_mm256_fmadd_pd(x1,tw_W16_1_rr,_mm256_mul_pd(zs,tw_W16_1_in)); }
        { __m256d zs=_mm256_permute_pd(x2,0x5);
          __m256d d=_mm256_sub_pd(x2,zs), s=_mm256_add_pd(x2,zs);
          x2=_mm256_mul_pd(_mm256_blend_pd(d,s,0xA),sqrt2_inv); }
        { __m256d zs=_mm256_permute_pd(x3,0x5);
          x3=_mm256_fmadd_pd(x3,tw_W16_3_rr,_mm256_mul_pd(zs,tw_W16_3_in)); }
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d pj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_even);
            x1=_mm256_add_pd(t1,pj); x3=_mm256_sub_pd(t1,pj); }
        }
        R16A_IL_CT_ST(&out[(1*os)*2 + off], x0);
        R16A_IL_CT_ST(&out[(5*os)*2 + off], x1);
        R16A_IL_CT_ST(&out[(9*os)*2 + off], x2);
        R16A_IL_CT_ST(&out[(13*os)*2 + off], x3);

        /* column k1=2 */
        x0 = _mm256_load_pd(&spill[2*4]);
        x1 = _mm256_load_pd(&spill[6*4]);
        x2 = _mm256_load_pd(&spill[10*4]);
        x3 = _mm256_load_pd(&spill[14*4]);
        { __m256d zs=_mm256_permute_pd(x1,0x5);
          __m256d d=_mm256_sub_pd(x1,zs), s=_mm256_add_pd(x1,zs);
          x1=_mm256_mul_pd(_mm256_blend_pd(d,s,0xA),sqrt2_inv); }
        x2 = _mm256_xor_pd(_mm256_permute_pd(x2,0x5), sign_even);
        { __m256d zs=_mm256_permute_pd(x3,0x5);
          __m256d s=_mm256_add_pd(x3,zs), d=_mm256_sub_pd(zs,x3);
          x3=_mm256_mul_pd(_mm256_blend_pd(_mm256_xor_pd(s,sign_all),d,0xA),sqrt2_inv); }
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d pj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_even);
            x1=_mm256_add_pd(t1,pj); x3=_mm256_sub_pd(t1,pj); }
        }
        R16A_IL_CT_ST(&out[(2*os)*2 + off], x0);
        R16A_IL_CT_ST(&out[(6*os)*2 + off], x1);
        R16A_IL_CT_ST(&out[(10*os)*2 + off], x2);
        R16A_IL_CT_ST(&out[(14*os)*2 + off], x3);

        /* column k1=3 */
        x0 = _mm256_load_pd(&spill[3*4]);
        x1 = _mm256_load_pd(&spill[7*4]);
        x2 = _mm256_load_pd(&spill[11*4]);
        x3 = _mm256_load_pd(&spill[15*4]);
        { __m256d zs=_mm256_permute_pd(x1,0x5);
          x1=_mm256_fmadd_pd(x1,tw_W16_3_rr,_mm256_mul_pd(zs,tw_W16_3_in)); }
        { __m256d zs=_mm256_permute_pd(x2,0x5);
          __m256d s=_mm256_add_pd(x2,zs), d=_mm256_sub_pd(zs,x2);
          x2=_mm256_mul_pd(_mm256_blend_pd(_mm256_xor_pd(s,sign_all),d,0xA),sqrt2_inv); }
        { __m256d zs=_mm256_permute_pd(x3,0x5);
          x3=_mm256_fmadd_pd(x3,tw_W16_9_rr,_mm256_mul_pd(zs,tw_W16_9_in)); }
        { __m256d t0=_mm256_add_pd(x0,x2), t1=_mm256_sub_pd(x0,x2);
          __m256d t2=_mm256_add_pd(x1,x3), t3=_mm256_sub_pd(x1,x3);
          x0=_mm256_add_pd(t0,t2); x2=_mm256_sub_pd(t0,t2);
          { __m256d pj=_mm256_xor_pd(_mm256_permute_pd(t3,0x5),sign_even);
            x1=_mm256_add_pd(t1,pj); x3=_mm256_sub_pd(t1,pj); }
        }
        R16A_IL_CT_ST(&out[(3*os)*2 + off], x0);
        R16A_IL_CT_ST(&out[(7*os)*2 + off], x1);
        R16A_IL_CT_ST(&out[(11*os)*2 + off], x2);
        R16A_IL_CT_ST(&out[(15*os)*2 + off], x3);

    }
}

#endif /* FFT_RADIX16_AVX2_CT_N1_IL_H */
